-- ============================================================
-- ファイル概要: hackathon-backend/migrations/001_init.sql
-- 役割: MySQLの初期スキーマとデモデータを定義し、ローカルでもクラウドでも同じ初期状態を再現します。
--
-- 実装上の注目点:
-- 日本語の商品名・説明・住所を扱うため、最初にutf8mb4を明示します。
-- CREATE TABLE群では、商品、購入、コメント、DM、通知、保存検索、支払い方法、AIチャット履歴の関係を定義します。
-- INSERT群では、検索・購入・出品履歴・推薦・売れ残り通知をすぐ確認できるデモデータを投入します。
-- ============================================================
-- 実装詳細メモ:
-- フリマアプリのER構造とデモデータを1ファイルで再現する初期マイグレーションです。
-- 外部キー、UNIQUE制約、検索INDEX、デモ用の初期商品がどの画面機能を支えるかを確認できます。
/*!40101 SET NAMES utf8mb4 */;
SET character_set_client = utf8mb4;
SET character_set_connection = utf8mb4;
SET character_set_results = utf8mb4;

-- ============================================================
-- ハッカソン用フリマアプリ 初期DBスキーマ
-- MySQL 8.0 / utf8mb4 を想定
-- ============================================================

-- users はログイン主体であり、出品者・購入者・通知受信者・問い合わせ投稿者の基点です。
-- balance_coins は購入に使える残高、sales_coins は売上金として分け、購入時と受取完了時の資金移動を説明しやすくしています。
-- rating_sum/rating_count は評価平均を都度再計算できるようにする集計列で、レビュー本文の履歴は purchases.rating_comment に残します。
CREATE TABLE IF NOT EXISTS users (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(80) NOT NULL,
  email VARCHAR(255) NOT NULL UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  balance_coins INT NOT NULL DEFAULT 0,
  sales_coins INT NOT NULL DEFAULT 0,
  rating_sum INT NOT NULL DEFAULT 0,
  rating_count INT NOT NULL DEFAULT 0,
  transaction_count INT NOT NULL DEFAULT 0,
  shipping_region VARCHAR(80) NULL,
  shipping_address TEXT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- items はフリマアプリの中心エンティティです。
-- product_code は画面に出す商品番号、id は内部JOIN用の主キーとして分けています。
-- image_url は旧実装名のままですが、現在は画像・動画Data URLのJSON配列も入るためMEDIUMTEXTにしています。
-- FULLTEXT INDEX はMySQL側のキーワード検索、通常INDEXはステータス・出品者・カテゴリ別の一覧表示を高速化します。
CREATE TABLE IF NOT EXISTS items (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  product_code VARCHAR(32) UNIQUE,
  seller_id BIGINT NOT NULL,
  title VARCHAR(120) NOT NULL,
  description TEXT NOT NULL,
  category VARCHAR(80) NOT NULL,
  condition_text VARCHAR(80) NOT NULL,
  price_yen INT NOT NULL,
  image_url MEDIUMTEXT NULL,
  delivery_method VARCHAR(120) NOT NULL DEFAULT '対面・配送相談',
  shipping_days INT NOT NULL DEFAULT 2,
  ship_from_region VARCHAR(80) NOT NULL DEFAULT '未設定',
  size VARCHAR(80) NULL,
  color VARCHAR(80) NULL,
  tags TEXT NULL,
  status ENUM('available', 'sold', 'canceled') NOT NULL DEFAULT 'available',
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT fk_items_seller FOREIGN KEY (seller_id) REFERENCES users(id),
  INDEX idx_items_status_updated_at (status, updated_at),
  INDEX idx_items_seller_id (seller_id),
  INDEX idx_items_category_status (category, status),
  FULLTEXT INDEX ft_items_title_description (title, description)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- purchases は「1商品につき1回だけ購入できる」取引状態を持ちます。
-- item_id にUNIQUEを付けることで二重購入をDB制約でも防ぎ、Repositoryのトランザクションと合わせて在庫整合性を守ります。
-- status は支払い済み、発送済み、受取完了、キャンセルの流れを表し、購入履歴画面の列分けに使います。
CREATE TABLE IF NOT EXISTS purchases (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  item_id BIGINT NOT NULL UNIQUE,
  buyer_id BIGINT NOT NULL,
  seller_id BIGINT NOT NULL,
  price_yen INT NOT NULL,
  status ENUM('paid', 'shipped', 'completed', 'canceled') NOT NULL DEFAULT 'paid',
  delivery_address TEXT NULL,
  shipping_deadline DATETIME NOT NULL,
  shipped_at DATETIME NULL,
  completed_at DATETIME NULL,
  rating INT NULL,
  rating_comment TEXT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_purchases_item FOREIGN KEY (item_id) REFERENCES items(id),
  CONSTRAINT fk_purchases_buyer FOREIGN KEY (buyer_id) REFERENCES users(id),
  CONSTRAINT fk_purchases_seller FOREIGN KEY (seller_id) REFERENCES users(id),
  INDEX idx_purchases_buyer_created_at (buyer_id, created_at),
  INDEX idx_purchases_seller_id (seller_id),
  INDEX idx_purchases_status_deadline (status, shipping_deadline)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- messages は商品詳細ページに出る公開コメントです。
-- parent_message_id で返信を表し、親コメントを削除した場合は返信もON DELETE CASCADEで消します。
-- sender_id/receiver_id を両方持つことで、出品者宛コメントと返信通知の宛先を明確にします。
CREATE TABLE IF NOT EXISTS messages (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  item_id BIGINT NOT NULL,
  parent_message_id BIGINT NULL,
  sender_id BIGINT NOT NULL,
  receiver_id BIGINT NOT NULL,
  body TEXT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT fk_messages_item FOREIGN KEY (item_id) REFERENCES items(id),
  CONSTRAINT fk_messages_parent FOREIGN KEY (parent_message_id) REFERENCES messages(id) ON DELETE CASCADE,
  CONSTRAINT fk_messages_sender FOREIGN KEY (sender_id) REFERENCES users(id),
  CONSTRAINT fk_messages_receiver FOREIGN KEY (receiver_id) REFERENCES users(id),
  INDEX idx_messages_item_updated_at (item_id, updated_at),
  INDEX idx_messages_parent_message_id (parent_message_id),
  INDEX idx_messages_receiver_id (receiver_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- private_messages は出品者と購入検討者だけが見るDMです。
-- 公開コメントとは分けて保存し、商品詳細ページでログインユーザーの関係者だけが取得できるようRepositoryで絞り込みます。
-- idx_private_messages_item_users は、商品IDと送受信者で会話を絞る一覧取得を支えます。
CREATE TABLE IF NOT EXISTS private_messages (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  item_id BIGINT NOT NULL,
  parent_private_message_id BIGINT NULL,
  sender_id BIGINT NOT NULL,
  receiver_id BIGINT NOT NULL,
  body TEXT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_private_messages_item FOREIGN KEY (item_id) REFERENCES items(id),
  CONSTRAINT fk_private_messages_parent FOREIGN KEY (parent_private_message_id) REFERENCES private_messages(id) ON DELETE CASCADE,
  CONSTRAINT fk_private_messages_sender FOREIGN KEY (sender_id) REFERENCES users(id),
  CONSTRAINT fk_private_messages_receiver FOREIGN KEY (receiver_id) REFERENCES users(id),
  INDEX idx_private_messages_item_users (item_id, sender_id, receiver_id),
  INDEX idx_private_messages_parent (parent_private_message_id),
  INDEX idx_private_messages_receiver_created_at (receiver_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- checklist は「気になる商品」保存機能です。
-- UNIQUE(user_id, item_id) により同じ商品を二重登録できないようにし、last_seen_updated_at は後で価格変更通知などに拡張できます。
CREATE TABLE IF NOT EXISTS checklist (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  item_id BIGINT NOT NULL,
  last_seen_updated_at DATETIME NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_checklist_user FOREIGN KEY (user_id) REFERENCES users(id),
  CONSTRAINT fk_checklist_item FOREIGN KEY (item_id) REFERENCES items(id),
  UNIQUE KEY uq_checklist_user_item (user_id, item_id),
  INDEX idx_checklist_user_created_at (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- notifications は購入、コメント、保存検索、AI販売改善提案などのユーザー通知をまとめます。
-- item_id はNULL許容にし、商品に紐づかない運営通知やマイページ系通知も同じ一覧に出せるようにしています。
CREATE TABLE IF NOT EXISTS notifications (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  item_id BIGINT NULL,
  title VARCHAR(120) NOT NULL,
  body TEXT NOT NULL,
  read_at DATETIME NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_notifications_user FOREIGN KEY (user_id) REFERENCES users(id),
  CONSTRAINT fk_notifications_item FOREIGN KEY (item_id) REFERENCES items(id),
  INDEX idx_notifications_user_created_at (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- saved_searches は商品一覧の検索条件をJSON文字列で保存します。
-- カラムを条件ごとに分けずquery_jsonにすることで、自然言語検索や新しいフィルタ追加にもマイグレーションなしで追従できます。
CREATE TABLE IF NOT EXISTS saved_searches (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  name VARCHAR(120) NOT NULL,
  query_json TEXT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_saved_searches_user FOREIGN KEY (user_id) REFERENCES users(id),
  INDEX idx_saved_searches_user_created_at (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- blocked_users はユーザー同士のブロック関係です。
-- blocker_id/blocked_id のペアをUNIQUEにし、コメント・DM・商品一覧の除外判定で同じ関係を重複登録しないようにします。
CREATE TABLE IF NOT EXISTS blocked_users (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  blocker_id BIGINT NOT NULL,
  blocked_id BIGINT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_blocked_users_blocker FOREIGN KEY (blocker_id) REFERENCES users(id),
  CONSTRAINT fk_blocked_users_blocked FOREIGN KEY (blocked_id) REFERENCES users(id),
  UNIQUE KEY uq_blocked_users_pair (blocker_id, blocked_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- support_messages はユーザーから運営への問い合わせ履歴です。
-- ハッカソンMVPでは管理者返信までは持たず、マイページで送信履歴を確認できる最小構成にしています。
CREATE TABLE IF NOT EXISTS support_messages (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  subject VARCHAR(120) NOT NULL DEFAULT '一般相談',
  body TEXT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_support_messages_user FOREIGN KEY (user_id) REFERENCES users(id),
  INDEX idx_support_messages_user_created_at (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- payment_methods は購入フローで使う支払い方法の表示情報です。
-- 実カード番号は保存せず、card_last4だけを保持します。is_defaultは購入画面で最初に使う支払い手段を示します。
CREATE TABLE IF NOT EXISTS payment_methods (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  label VARCHAR(120) NOT NULL,
  card_last4 CHAR(4) NOT NULL,
  holder_name VARCHAR(120) NOT NULL,
  expiry_month TINYINT NOT NULL,
  expiry_year SMALLINT NOT NULL,
  is_default BOOLEAN NOT NULL DEFAULT FALSE,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_payment_methods_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  INDEX idx_payment_methods_user_default (user_id, is_default),
  INDEX idx_payment_methods_user_created_at (user_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- AI対話ページのスレッド情報です。
-- 商品ごとのコメントとは別に、ユーザーが自由相談を話題ごとに保存できるようにします。
CREATE TABLE IF NOT EXISTS ai_chat_threads (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  user_id BIGINT NOT NULL,
  title VARCHAR(120) NOT NULL DEFAULT '新しい相談',
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT fk_ai_chat_threads_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  INDEX idx_ai_chat_threads_user_updated_at (user_id, updated_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- AI対話ページの発言履歴です。
-- role=user はユーザー発言、role=assistant はAI回答を表し、notice/used_fallbackで外部AIフォールバック状態も残します。
CREATE TABLE IF NOT EXISTS ai_chat_messages (
  id BIGINT AUTO_INCREMENT PRIMARY KEY,
  thread_id BIGINT NOT NULL,
  role ENUM('user', 'assistant') NOT NULL,
  body TEXT NOT NULL,
  notice TEXT NULL,
  used_fallback BOOLEAN NOT NULL DEFAULT FALSE,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_ai_chat_messages_thread FOREIGN KEY (thread_id) REFERENCES ai_chat_threads(id) ON DELETE CASCADE,
  INDEX idx_ai_chat_messages_thread_created_at (thread_id, created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- ============================================================
-- デモ用初期データ
-- 4名のユーザーと20件の商品を初期投入します。
-- DBを作り直した直後でも、商品一覧・検索・おすすめ・出品履歴のデモができます。
--
-- 文字化け対策:
-- このファイル冒頭で SET NAMES utf8mb4 を実行しています。
-- さらに投入コマンドでも --default-character-set=utf8mb4 を付けると、
-- 日本語の商品名・説明・発送元・タグが正しく保存されます。
--
-- 商品カテゴリ、状態、受け渡し方法、サイズ、色は、
-- フロントエンド src/formOptions.ts のプルダウン候補に存在する値だけを使っています。
-- ============================================================

-- 【デモデータ投入】users に初期データを入れ、ログイン直後からデモできる状態を作ります。
INSERT INTO users (id, name, email, password_hash, balance_coins, sales_coins, rating_sum, rating_count, transaction_count, shipping_region, shipping_address) VALUES
  (1, 'user1', 'user1@example.com', '$2a$10$BE9RamaQzyRtrfg02DwGyuZzIEyamfWbmRyD0ywq6qvOsAUfM5azS', 500, 20000, 15, 3, 3, '東京都', '東京都文京区本郷1-1-1'),
  (2, 'user2', 'user2@example.com', '$2a$10$SbJUqn4yuDsuBPTOeWsSY.Y9g50XsRI/IV6wkgE43y6QZyGjAdKFm', 1000, 23500, 15, 3, 3, '千葉県', '千葉県千葉市中央区弁天1-1-1'),
  (3, 'user3', 'user3@example.com', '$2a$10$VcC9IuB8fsXuXQGp5U8E9O2iWORBJ14l1F65uAQshRY5iFixdbotq', 10000, 1000, 5, 1, 1, '神奈川県', '神奈川県横浜市西区みなとみらい1-1-1'),
  (4, 'user4', 'user4@example.com', '$2a$10$V3MIkZ/RZVdX2Q1YJT9wlOIBgO./YzVOIJIQr.tLlJuSJnvCW7NXi', 100000, 8000, 5, 1, 1, '埼玉県', '埼玉県さいたま市浦和区高砂1-1-1')
ON DUPLICATE KEY UPDATE name=VALUES(name), password_hash=VALUES(password_hash), balance_coins=VALUES(balance_coins), sales_coins=VALUES(sales_coins), rating_sum=VALUES(rating_sum), rating_count=VALUES(rating_count), transaction_count=VALUES(transaction_count), shipping_region=VALUES(shipping_region), shipping_address=VALUES(shipping_address);

